using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// FIX 1 (ValidateScopes): Changed Singleton → Scoped to eliminate the captive-
// dependency on the scoped IUserService. .NET 9 enables ValidateScopes in
// Development by default and would throw InvalidOperationException at startup.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// FIX 2 (SocketsHttpHandler): .NET 9 HttpClientFactory uses SocketsHttpHandler
// by default. The old cast to HttpClientHandler would throw InvalidCastException.
// Replaced ConfigureHttpMessageHandlerBuilder (also obsolete) with
// ConfigurePrimaryHttpMessageHandler using SocketsHttpHandler directly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false });
// FIX 3 (Header redaction): .NET 9 redacts ALL header values in Trace-level
// HttpClientFactory logs by default. Allowlist non-sensitive headers so they
// remain visible when debugging request headers.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(header =>
        header != "Accept"
        && header != "Content-Type"
        && header != "Cache-Control"
        && header != "User-Agent"));
// FIX 4 (Forwarded Headers): .NET 9 ForwardedHeadersMiddleware silently ignores
// X-Forwarded-* headers from proxies not in KnownProxies / KnownNetworks.
// Add your reverse-proxy address here (replace with your actual proxy IP).
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

